// ── Parse incoming Botsab webhook ──────────────────────────────────────────
const body  = $json.body || {};
const event = body.event;
const instanceId = body.instanceId || '';
const enriched   = body.data?.enriched || {};

// Only handle message.received that are group mentions with text
if (event !== 'message.received')           return [{ json: { skip: true, reason: 'wrong event' } }];
if (!enriched.isGroup)                      return [{ json: { skip: true, reason: 'not group' } }];
if (!enriched.isMentioned)                  return [{ json: { skip: true, reason: 'not mentioned' } }];
const rawText = (enriched.text || '').trim();
if (!rawText)                               return [{ json: { skip: true, reason: 'empty text' } }];

// ── Rate limit: 1 message per group per 3 s ────────────────────────────────
if (!globalThis._botsabRL) globalThis._botsabRL = {};
const now = Date.now();
const groupId = enriched.groupId || enriched.remoteJid || '';
if (now - (globalThis._botsabRL[groupId] || 0) < 3000) {
  return [{ json: { skip: true, reason: 'rate limited' } }];
}
globalThis._botsabRL[groupId] = now;

// ── Strip @mentions from query ─────────────────────────────────────────────
const query = rawText.replace(/@\d+[\s]*/g, '').trim();

// ── Detect slash commands (/help, /reset, /about) ─────────────────────────
const cmdMatch    = query.match(/^\/([\w]+)(?:\s+(.*))?$/);
const isCommand   = !!cmdMatch;
const commandName = cmdMatch ? cmdMatch[1].toLowerCase() : null;
const commandArg  = cmdMatch ? (cmdMatch[2] || '').trim() : null;

return [{ json: {
  skip: false,
  instanceId,
  groupId,
  senderId:    enriched.senderId || '',
  rawText,
  query:       query || rawText,
  isCommand,
  commandName,
  commandArg,
} }];

// ── Handle slash commands ─────────────────────────────────────────────────
const { instanceId, groupId, commandName } = $json;

if (!globalThis._botsabHistory) globalThis._botsabHistory = {};
const key = `${instanceId}:${groupId}`;

let reply;
switch (commandName) {
  case 'help':
    reply =
      '🤖 AI Assistant — Commands\n' +
      '• /help   — show this list\n' +
      '• /reset  — clear conversation history\n' +
      '• /about  — about this bot\n\n' +
      'Or just tag me with any question!';
    break;

  case 'reset':
    delete globalThis._botsabHistory[key];
    reply = '✅ Conversation history cleared. Fresh start!';
    break;

  case 'about':
    reply =
      '🤖 Powered by Claude AI (Anthropic), integrated via Botsab.\n' +
      'I remember the last 10 messages in this group. Tag me anytime!';
    break;

  default:
    reply = `❓ Unknown command: /${commandName}\nType /help to see available commands.`;
}

return [{ json: { instanceId, groupId, reply } }];

// ── Build Claude API request with conversation history ─────────────────────
const { instanceId, groupId, senderId, query } = $json;

// ── System prompt — customise this ────────────────────────────────────────
const today = new Date().toLocaleDateString('en-IN', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
});
const SYSTEM = `You are a helpful AI assistant embedded in a WhatsApp group via Botsab.

Guidelines:
- Be concise: reply in under 200 words unless the question genuinely needs more.
- Plain text only — NO markdown bold (**), NO italic (_), NO headers (##), NO triple backticks.
- Use bullet points with • if listing things.
- Friendly, warm tone.
- If you do not know something, say so honestly.
- Do not repeat the question back.
- Today is ${today}.`;

// ── Load per-group history ─────────────────────────────────────────────────
if (!globalThis._botsabHistory) globalThis._botsabHistory = {};
const key = `${instanceId}:${groupId}`;
if (!globalThis._botsabHistory[key]) globalThis._botsabHistory[key] = [];

const history  = globalThis._botsabHistory[key];
const messages = [ ...history.slice(-20), { role: 'user', content: query } ];

// ── Build the full Anthropic request body ──────────────────────────────────
const claudeBody = JSON.stringify({
  model:      'claude-haiku-4-5-20251001',
  max_tokens: 600,
  system:     SYSTEM,
  messages,
});

return [{ json: { instanceId, groupId, senderId, query, claudeBody } }];

// ── Error fallback when Claude API is unreachable ─────────────────────────
const ctx = $('Build AI Request').item.json;
return [{ json: {
  instanceId: ctx.instanceId,
  groupId:    ctx.groupId,
  reply:      '⚠️ Sorry, I could not reach the AI service right now. Please try again in a moment.',
} }];

// ── Extract reply text + persist to history ───────────────────────────────
const aiResp   = $json;
const replyText = aiResp.content?.[0]?.text?.trim()
  ?? 'Sorry, I could not generate a response. Please try again.';

const ctx = $('Build AI Request').item.json;
const { instanceId, groupId, query } = ctx;

// Persist exchange
if (!globalThis._botsabHistory) globalThis._botsabHistory = {};
const key = `${instanceId}:${groupId}`;
if (!globalThis._botsabHistory[key]) globalThis._botsabHistory[key] = [];

globalThis._botsabHistory[key].push(
  { role: 'user',      content: query     },
  { role: 'assistant', content: replyText },
);

// Keep last 20 messages (10 exchanges)
if (globalThis._botsabHistory[key].length > 20) {
  globalThis._botsabHistory[key] = globalThis._botsabHistory[key].slice(-20);
}

return [{ json: { instanceId, groupId, reply: replyText } }];
